import{_ as i,o as a,c as o,a2 as t}from"./chunks/framework.Bix3-HpO.js";const f=JSON.parse('{"title":"Creating Review Pages","description":"Creating Review Pages with Akurai Theme","frontmatter":{"title":"Creating Review Pages","description":"Creating Review Pages with Akurai Theme","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/creating-review-pages"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/creating-review-pages"}],["meta",{"property":"og:title","content":"Creating Review Pages"}],["meta",{"property":"og:description","content":"Creating Review Pages with Akurai Theme"}],["meta",{"name":"twitter:title","content":"Creating Review Pages"}],["meta",{"name":"twitter:description","content":"Creating Review Pages with Akurai Theme"}]]},"headers":[],"relativePath":"docs/akurai/creating-review-pages.md","filePath":"docs/akurai/creating-review-pages.md"}'),r={name:"docs/akurai/creating-review-pages.md"};function s(n,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="creating-review-pages" tabindex="-1">Creating Review Pages <a class="header-anchor" href="#creating-review-pages" aria-label="Permalink to &quot;Creating Review Pages&quot;">​</a></h1><p>In your WordPress dashboard you will find a new menu item called <strong>Reviews</strong> right below the <strong>Pages</strong> menu link. Click <code>Add New</code> to add a new review.</p><hr><h2 id="review-fields" tabindex="-1">Review Fields <a class="header-anchor" href="#review-fields" aria-label="Permalink to &quot;Review Fields&quot;">​</a></h2><p>Besides adding your review title and content as usual, you&#39;ll find <strong>Review Fields</strong> section below page content. Here you can define properties for each review. The fields are in separate sections and have descriptions to make it easy for you to fill them in. These properties are used all over the website, please make sure to fill them in.</p><h3 id="main-fields" tabindex="-1">Main Fields <a class="header-anchor" href="#main-fields" aria-label="Permalink to &quot;Main Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-main.jpg" alt="akurai-review-fields-main"></p><p>In this section you&#39;ll define the main fields for any review such as:</p><ul><li>Name</li><li>Images/Logos</li><li>Affiliate Link URL</li><li>Review Page Hero Colors</li></ul><p>The name, image and affiliate URL are used in all shortcodes, blocks, widgets and review page and hero colors are there to help you customize each review page.</p><h3 id="bonus-fields" tabindex="-1">Bonus Fields <a class="header-anchor" href="#bonus-fields" aria-label="Permalink to &quot;Bonus Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-bonus.jpg" alt="akurai-review-fields-bonus"></p><p>Bonus fields are for defining sportsbook bonuses. You can define an optional <strong>Shortcode Bonus</strong> if you want to display a different or differently formatted bonus in shortcodes.</p><h3 id="ratings-fields" tabindex="-1">Ratings Fields <a class="header-anchor" href="#ratings-fields" aria-label="Permalink to &quot;Ratings Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-ratings.jpg" alt="akurai-review-fields-ratings"></p><p>First you define the main sportsbook rating which is used all over the website n shortcodes, widgets, etc.</p><p>The second part for <strong>Ratings</strong> is where you define different ratings to display in review pages <strong>Ratings</strong> block/shortcode.</p><h3 id="terms-fields" tabindex="-1">Terms Fields <a class="header-anchor" href="#terms-fields" aria-label="Permalink to &quot;Terms Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-terms.jpg" alt="akurai-review-fields-terms"></p><p>You can define 2 fields for sportsbook terms and conditions, first the longer and 2nd the shorter version. later in blocks/shortcodes you can choose to display one of them.</p><h3 id="info-fields" tabindex="-1">Info Fields <a class="header-anchor" href="#info-fields" aria-label="Permalink to &quot;Info Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-info.jpg" alt="akurai-review-fields-info"></p><p>Define basic information about the sportsbook and display them in <code>Info</code> block (or <code>[info]</code> shortcode) in review pages.</p><h3 id="pros-cons-fields" tabindex="-1">Pros &amp; Cons Fields <a class="header-anchor" href="#pros-cons-fields" aria-label="Permalink to &quot;Pros &amp; Cons Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-pros-cons.jpg" alt="akurai-review-fields-pros-cons"></p><p>Define pros and cons of the sportsbook and display them in <code>Pros &amp; Cons</code> block (or <code>[pros_cons]</code> shortcode) in review pages.</p><h3 id="banking-fields" tabindex="-1">Banking Fields <a class="header-anchor" href="#banking-fields" aria-label="Permalink to &quot;Banking Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-banking.jpg" alt="akurai-review-fields-banking"></p><p>Define deposit and withdrawal methods provided by the sportsbook and display them in <code>Banking</code> block (or <code>[banking]</code> shortcode) in review pages.</p><h3 id="offer-fields" tabindex="-1">Offer Fields <a class="header-anchor" href="#offer-fields" aria-label="Permalink to &quot;Offer Fields&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-offer.jpg" alt="akurai-review-fields-offer"></p><p>Define the main offers of the sportsbook such as sportsbook, casino, poker, etc. and their bonuses and display them in <code>Offer</code> block (or <code>[offer]</code> shortcode) in review pages.</p><h3 id="related-reviews" tabindex="-1">Related Reviews <a class="header-anchor" href="#related-reviews" aria-label="Permalink to &quot;Related Reviews&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-related.jpg" alt="akurai-review-fields-related"></p><p>You can choose to display related reviews section at the end of each review page. For that you need to select at least 1 (max 3) other review pages.</p><h3 id="supported-countries" tabindex="-1">Supported Countries <a class="header-anchor" href="#supported-countries" aria-label="Permalink to &quot;Supported Countries&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-countries.jpg" alt="akurai-review-fields-countries"></p><p>Define the supported countries of the sportsbook and display them in <code>Countries</code> block (or <code>[countries]</code> shortcode) in review pages.</p><h3 id="additional-info" tabindex="-1">Additional Info <a class="header-anchor" href="#additional-info" aria-label="Permalink to &quot;Additional Info&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/review-fields-additional-info.jpg" alt="akurai-review-fields-countries"></p><p>Define some additional info fields here that are used on table/grid filters mostly.</p><h3 id="review-snippet" tabindex="-1">Review Snippet <a class="header-anchor" href="#review-snippet" aria-label="Permalink to &quot;Review Snippet&quot;">​</a></h3><p>For all your review pages Akurai generates <strong>Review Snippet Structured data</strong> (schema.org) markup. The rating value used is the &quot;Overall Rating&quot; field from <a href="#ratings-fields">Rating Fields</a> section. It is generated automatically so you don&#39;t need to do anything, however you can turn it off if you decide so. You can test your pages <a href="https://search.google.com/structured-data/testing-tool" target="_blank" rel="noreferrer">here</a>.</p>',43)])])}const g=i(r,[["render",s]]);export{f as __pageData,g as default};
